}

selector::after {
    position: absolute;
    content: "";
    border-radius: 20px;
    border: 1px solid rgba(0, 0, 0, 0.1);
    width: calc(100% + 1.8rem);
    height: calc(100% + 1.8rem);
    top: -0.9rem;
    left: -0.9rem;
    pointer-events: none;
}

/* Botão base */
selector .elementor-button {
  position: relative;
  overflow: hidden;
  
  pointer-events: none;
  cursor: default; /* ou auto */
}

/* Faixa de brilho */
selector .elementor-button::before {
  content: "";
  position: absolute;

  width: 90px;
  height: 160%;
  bottom: 0;
  left: -10%;
  transform: translateX(-50%) skew(-25deg);

  background-color: initial;
  background-image: linear-gradient(
    10deg,
    #ffffff 12.81%,
    rgba(209, 210, 234, 0) 66.66%
  );
  filter: blur(4px);

  animation: shinery 3s ease-in-out infinite;
}

/* Animação */
@keyframes shinery {
  0%,
  to {
    left: -10%;
    opacity: 0;
  }

  20% {
    opacity: 1;
  }

  48% {
    left: 120%;
    opacity: 1;
  }

  51% {
    opacity: 0;
  }
}

